// formatDate は日付をユーザーのタイムゾーンでフォーマットします
func formatDate(t time.Time, loc *time.Location) string {
	if loc == nil {
		loc = time.FixedZone("Asia/Tokyo", 9*60*60)
	}
	return t.In(loc).Format("2006/01/02")
}

